-- PostgreSQL schema for storing GPS locations and fuel sensor data\n\nCREATE TABLE gps_locations (\n    id SERIAL PRIMARY KEY,\n    device_id VARCHAR(50),\n    latitude DOUBLE PRECISION NOT NULL,\n    longitude DOUBLE PRECISION NOT NULL,\n    recorded_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE TABLE fuel_sensor_data (\n    id SERIAL PRIMARY KEY,\n    device_id VARCHAR(50),\n    fuel_level DOUBLE PRECISION NOT NULL,\n    temperature DOUBLE PRECISION NOT NULL,\n    recorded_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE INDEX idx_device_id_gps ON gps_locations(device_id);\nCREATE INDEX idx_device_id_fuel ON fuel_sensor_data(device_id);\n